        // Example usage
        String str = "Hello";
        List<Integer> numbers = Arrays.asList(1, 2, 3, 4, 5);
        System.out.println(computeSum(str, numbers)); // Example output
    }

    public static int computeSum(String str, List<Integer> numbers) {
        int sum = 0;
        for (int number : numbers) {
            sum += number;
        }
        return sum + str.length();
    }
}
