```javascript
function next_smallest(lst) {
    if (lst.length < 2) {
        return null;
    }

    const uniqueColors = [...new Set(lst)];
    uniqueColors.sort();

    if (uniqueColors.length < 2) {
        return null;
    }

    return uniqueColors[1];
}

